  OPTIONAL { ?film dbo:releaseDate ?date1 }
  OPTIONAL { ?film dbp:releaseDate ?date2 }
  OPTIONAL { ?film dbp:year ?yearLit }
  OPTIONAL { ?film dbo:year ?yearLit2 }

