PREFIX dbp: <http://dbpedia.org/property/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX dbr: <http://dbpedia.org/resource/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dbo: <http://dbpedia.org/ontology/>
SELECT ?series (SAMPLE(?seriesLabel) AS ?label) (COUNT(DISTINCT ?char) AS ?numChars) WHERE {
  VALUES ?person { dbr:Stephen_Merchant }
  {
    ?series dbo:executiveProducer ?person .
  } UNION {
    ?series dbp:executiveProducer ?person .
  }
  # Prefer English label
  OPTIONAL { ?series rdfs:label ?seriesLabel FILTER(lang(?seriesLabel) = 'en') }
  # candidate character links/literals
  {
    ?series dbp:characters ?char .
  } UNION {
    ?series dbp:character ?char .
  } UNION {
    ?series dbo:fictionalCharacter ?char .
  } UNION {
    ?series dbo:character ?char .
  } UNION {
    # if starring points to a fictional character resource (typed as dbo:FictionalCharacter)
    ?series dbo:starring ?starring .
    ?starring rdf:type ?starringType .
    FILTER(regex(str(?starringType), "FictionalCharacter","i") || ?starringType = dbo:FictionalCharacter)
    BIND(?starring AS ?char)
  }
}
GROUP BY ?series
ORDER BY DESC(?numChars)
LIMIT 50

