  } UNION {
    ?game dbo:series ?series .
  }
  OPTIONAL { ?game dbo:publisher ?publisherIRI . }
  OPTIONAL { ?game dbp:publisher ?publisherIRI2 . }
  BIND(COALESCE(?publisherIRI, ?publisherIRI2) AS ?publisherRaw)
  BIND(IF(isIRI(?publisherRaw), ?publisherRaw, STR(?publisherRaw)) AS ?publisher)
  OPTIONAL {
    FILTER(isIRI(?publisher))
    ?publisher rdfs:label ?publisherLabel . FILTER(lang(?publisherLabel) = 'en')
  }
}
ORDER BY ?publisherLabel

