PREFIX dbo: <http://dbpedia.org/ontology/>
SELECT DISTINCT ?spouse ?spouseLabel ?study ?studyLabel WHERE {
  VALUES ?person { dbr:Aung_San_Suu_Kyi }
  # spouse via dbo:spouse or dbp:spouse
  { ?person dbo:spouse ?spouse } UNION { ?person dbp:spouse ?spouse }
  # education/alma mater via several common predicates; allow literals too
  OPTIONAL { ?spouse dbo:almaMater ?study . }
  OPTIONAL { ?spouse dbo:education ?study . }
  OPTIONAL { ?spouse dbp:almaMater ?study . }
  OPTIONAL { ?spouse dbp:education ?study . }
  # if study is literal return it as a literal node; otherwise get label
  OPTIONAL { ?spouse rdfs:label ?spouseLabel FILTER(lang(?spouseLabel)='en') }
  OPTIONAL { ?study rdfs:label ?studyLabel FILTER(lang(?studyLabel)='en') }
  # also prefer to capture literal literal studies from dbp:* as ?studyLabel when ?study is a literal
  BIND(IF(isLiteral(?study), STR(?study), ?studyLabel) AS ?studyLabelFinal)
} LIMIT 50

